export function buildCompactionHint(rawRefId) {
    if (rawRefId) {
        return `raw saved: \`tokenjuice cat ${rawRefId}\`.`;
    }
    return "need raw? `tokenjuice wrap --raw -- <command>`.";
}
export function buildCompactedOutputContext(inlineText) {
    return `${inlineText}\n\n${buildCompactionHint()}`;
}
export function writeHookJsonLine(payload) {
    process.stdout.write(`${JSON.stringify(payload)}\n`);
}
export function writeEmptyHookJsonLine() {
    writeHookJsonLine({});
}
